  1	import {
  2	  Alert,
  3	  Button,
  4	  Form,
  5	  FormGroup,
  6	  FormHelperText,
  7	  HelperText,
  8	  HelperTextItem,
  9	  Modal,
 10	  ModalVariant,
 11	  TextInput,
 12	} from "@patternfly/react-core";
 13	import { getFieldId } from "copiedFromConsole/formik-fields/field-utils";
 14	import * as React from "react";
 15	
 16	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 17	import { NodeHealthCheck } from "data/types";
 18	import { editNodeHealthCheckPauseReasons } from "apis/nodeHealthCheckApis";
 19	import { WithRemoveButton } from "components/shared/WithRemoveButton";
 20	import AddMoreButton from "components/shared/AddMoreButton";
 21	import { clone } from "lodash-es";
 22	
 23	type PauseReasonFieldProps = {
 24	  onRemove(idx: number): void;
 25	  onAdd(): void;
 26	  onEdit(idx: number, value: string): void;
 27	  pauseReasons: string[];
 28	};
 29	
 30	const PauseReasonsField: React.FC<PauseReasonFieldProps> = ({
 31	  onRemove,
 32	  onAdd,
 33	  onEdit,
 34	  pauseReasons,
 35	}) => {
 36	  const { t } = useNodeHealthCheckTranslation();
 37	  return (
 38	    <>
 39	      {pauseReasons.map((value, idx) => {
 40	        return (
 41	          <FormGroup
 42	            fieldId={getFieldId("pause-reason", "input")}
 43	            isRequired
 44	            label={t("Pause reason")}
 45	            key={idx}
 46	            data-index={idx}
 47	            data-test="pause-reason-field"
 48	          >
 49	            <WithRemoveButton
 50	              onClick={() => onRemove(idx)}
 51	              isDisabled={pauseReasons.length === 1 && !pauseReasons[0]}
 52	              key={idx}
 53	              dataTest="remove-pause-reason"
 54	            >
 55	              <TextInput
 56	                name={`pause-reason-${idx}`}
 57	                value={pauseReasons[idx]}
 58	                onChange={(_, value) => onEdit(idx, value)}
 59	                data-test="pause-reason-input"
 60	                data-index={idx}
 61	                aria-label="pause reason"
 62	              />
 63	            </WithRemoveButton>
 64	            <FormHelperText>
 65	              <HelperText>
 66	                <HelperTextItem>
 67	                  {t(
 68	                    "Describe the reason for pausing this NodeHealthCheck remediation."
 69	                  )}
 70	                </HelperTextItem>
 71	              </HelperText>
 72	            </FormHelperText>
 73	          </FormGroup>
 74	        );
 75	      })}
 76	
 77	      <AddMoreButton
 78	        onClick={() => {
 79	          onAdd();
 80	        }}
 81	        dataTest="add-pause-reason"
 82	      />
 83	    </>
 84	  );
 85	};
 86	
 87	type PauseReasonsModalProps = {
 88	  failureErrorMessage: string;
 89	  title: string;
 90	  confirmButtonText: string;
 91	  nodeHealthCheck: NodeHealthCheck;
 92	  onClose(): void;
 93	  isOpen: boolean;
 94	  initialPauseReasons: string[];
 95	};
 96	
 97	const EditPauseReasonsModal: React.FC<PauseReasonsModalProps> = ({
 98	  failureErrorMessage,
 99	  title,
100	  confirmButtonText,
101	  nodeHealthCheck,
102	  onClose,
103	  isOpen,
104	  initialPauseReasons,
105	}) => {
106	  const [pauseReasons, setPauseReasons] =
107	    React.useState<string[]>(initialPauseReasons);
108	  const [isSubmitting, setIsSubmitting] = React.useState<boolean>();
109	  const [error, setError] = React.useState<boolean>();
110	  const { t } = useNodeHealthCheckTranslation();
111	
112	  const onSubmit = async () => {
113	    setIsSubmitting(true);
114	    try {
115	      await editNodeHealthCheckPauseReasons(nodeHealthCheck, pauseReasons);
116	    } catch (err) {
117	      setError(err);
118	      setIsSubmitting(false);
119	      return;
120	    }
121	    setIsSubmitting(false);
122	    onClose();
123	  };
124	
125	  const onAdd: PauseReasonFieldProps["onAdd"] = () => {
126	    const newPauseReasons = clone(pauseReasons);
127	    newPauseReasons.push("");
128	    setPauseReasons(newPauseReasons);
129	  };
130	
131	  const onRemove: PauseReasonFieldProps["onRemove"] = (idx: number) => {
132	    const newPauseReasons = clone(pauseReasons);
133	    if (pauseReasons.length === 1) {
134	      newPauseReasons[0] = "";
135	    } else {
136	      newPauseReasons.splice(idx, 1);
137	    }
138	    setPauseReasons(newPauseReasons);
139	  };
140	
141	  const onEdit: PauseReasonFieldProps["onEdit"] = (
142	    idx: number,
143	    value: string
144	  ) => {
145	    const newPauseReasons = clone(pauseReasons);
146	    newPauseReasons[idx] = value;
147	    setPauseReasons(newPauseReasons);
148	  };
149	
150	  const hasEmptyValue = (): boolean => {
151	    return pauseReasons.filter((pauseReason) => !pauseReason).length > 0;
152	  };
153	
154	  return (
155	    <Modal
156	      isOpen={isOpen}
157	      onClose={onClose}
158	      variant={ModalVariant.small}
159	      title={title}
160	      className="nhc-modal"
161	      actions={[
162	        <Button
163	          key="confirm"
164	          variant="primary"
165	          onClick={() => void onSubmit()}
166	          isDisabled={hasEmptyValue() || isSubmitting}
167	          isLoading={isSubmitting}
168	          data-test="confirm"
169	          type="submit"
170	        >
171	          {confirmButtonText}
172	        </Button>,
173	        <Button
174	          key="cancel"
175	          variant="secondary"
176	          onClick={onClose}
177	          data-test="cancel"
178	          isDisabled={isSubmitting}
179	        >
180	          {t("Cancel")}
181	        </Button>,
182	      ]}
183	    >
184	      <Form>
185	        <PauseReasonsField {...{ onAdd, onRemove, pauseReasons, onEdit }} />
186	        {error && (
187	          <Alert variant="danger" title={failureErrorMessage} isInline />
188	        )}
189	      </Form>
190	    </Modal>
191	  );
192	};
193	
194	export default EditPauseReasonsModal;

